// Extract lead data if AI captured it
const output = $input.all()[0].json.output || '';
const leadMatch = output.match(/\[LEAD_CAPTURED\](.*?)\[\/LEAD_CAPTURED\]/s);

if (leadMatch) {
  try {
    const leadData = JSON.parse(leadMatch[1]);
    return [{ json: { ...leadData, captured: true } }];
  } catch (e) {
    return [{ json: { captured: false } }];
  }
}

return [{ json: { captured: false } }];

